mapper.delete:
		/*
             SQL ID : SrvyQstnDAO.srvypprQstnDelete
             설  명  : 설문지문항삭제
         */
        DELETE FROM TB_LMS_SRVY_QSTN
         WHERE SRVYPPR_ID = #{srvypprId}

mapper.insert:
		/*
             SQL ID : SrvyQstnDAO.srvyQstnRegist
             설  명  : 설문문항등록
         */
        INSERT INTO TB_LMS_SRVY_QSTN (
        	  SRVY_QSTN_ID
			, SRVYPPR_ID
			, QSTN_GBNCD
			, QSTN_RSPNS_TYCD
			, QSTN_SEQNO
			, QSTN_TTL
			, QSTN_CTS
			, ESNTL_RSPNSYN
			, ETC_INPT_USEYN
			, SRVY_MVMN_USEYN
			, RGTR_ID
			, REG_DTTM
        ) VALUES (
        	  #{srvyQstnId}
			, #{srvypprId}
			, #{qstnGbncd}
			, #{qstnRspnsTycd}
			, #{qstnSeqno}
			, #{qstnTtl}
			, #{qstnCts}
			, NVL(#{esntlRspnsyn}, 'N')
			, NVL(#{etcInptUseyn}, 'N')
			, NVL(#{srvyMvmnUseyn}, 'N')
			, #{rgtrId}
			, FN_DTTM()
        )

mapper.update:
		/*
             SQL ID : SrvyQstnDAO.srvyQstnModify
             설  명  : 설문문항수정
         */
        UPDATE TB_LMS_SRVY_QSTN SET
        	  MDFR_ID = #{rgtrId}
        	, MOD_DTTM = FN_DTTM()

        	, QSTN_GBNCD = #{qstnGbncd}


			, QSTN_RSPNS_TYCD = #{qstnRspnsTycd}


			, QSTN_SEQNO = #{qstnSeqno}


			, QSTN_TTL = #{qstnTtl}


			, QSTN_CTS = #{qstnCts}


			, ESNTL_RSPNSYN = #{esntlRspnsyn}


			, ETC_INPT_USEYN = #{etcInptUseyn}


			, SRVY_MVMN_USEYN = #{srvyMvmnUseyn}


			, DELYN = #{delyn}

         WHERE SRVY_QSTN_ID = #{srvyQstnId}

		/*
             SQL ID : SrvyQstnDAO.srvyQstnDelNSeqnoModify
             설  명  : 설문문항미삭제순번수정
         */
        UPDATE TB_LMS_SRVY_QSTN SET
        	  MDFR_ID = #{rgtrId}
        	, MOD_DTTM = FN_DTTM()
        	, QSTN_SEQNO = QSTN_SEQNO - 1
         WHERE SRVYPPR_ID = #{srvypprId}
           AND QSTN_SEQNO  >  #{qstnSeqno}

mapper.select:
		/*
             SQL ID : SrvyQstnDAO.srvyQstnSelect
             설  명  : 설문문항조회
         */
        SELECT
        	*
          FROM TB_LMS_SRVY_QSTN
         WHERE SRVYPPR_ID = #{srvypprId}
           AND SRVY_QSTN_ID = #{srvyQstnId}

mapper.insert:
/* SQL ID : SrvyQstnDAO.srvyQstnCopy 설 명 : 설문문항가져오기 */ INSERT INTO TB_LMS_SRVY_QSTN ( SRVY_QSTN_ID , SRVYPPR_ID , QSTN_GBNCD , QSTN_RSPNS_TYCD , QSTN_TTL , QSTN_CTS , ESNTL_RSPNSYN , ETC_INPT_USEYN , RGTR_ID , REG_DTTM , QSTN_SEQNO ) SELECT A.* , ROW_NUMBER() OVER(ORDER BY QSTN_TTL) AS QSTN_SEQNO FROM (
SELECT #{item.srvyQstnId} AS SRVY_QSTN_ID , #{item.srvypprId} AS SRVYPPR_ID , Q.QSTN_GBNCD , Q.QSTN_RSPNS_TYCD , Q.QSTN_TTL , Q.QSTN_CTS , Q.ESNTL_RSPNSYN , Q.ETC_INPT_USEYN , #{item.rgtrId} AS RGTR_ID , FN_DTTM() AS REG_DTTM FROM DUAL LEFT JOIN TB_LMS_SRVY_QSTN Q ON Q.SRVY_QSTN_ID = #{item.copySrvyQstnId}
) A
